SELECT AVG(close_price) 
FROM market_data 
WHERE date >= '2023-05-01';

SELECT AVG(close_price) 
FROM market_data 
WHERE date = '2022-02-01';

SELECT COUNT(DISTINCT a.alert_id) AS alert_count
FROM alerts a
JOIN alert_triggers at ON a.alert_id = at.alert_id;

SELECT 
    (SELECT AVG(close_price) FROM market_data WHERE source = 'BSE') AS avg_close_price_BSE,
    (SELECT COUNT(*) FROM financial_instruments WHERE sector = 'Healthcare') AS num_healthcare_instruments;

SELECT DISTINCT a.user_id, a.instrument_id
FROM users u
INNER JOIN alerts a ON u.user_id = a.user_id;

SELECT 
    (SELECT MAX(market_cap) FROM market_data) - 
    (SELECT AVG(triggered_volume) FROM alert_triggers) AS Result;

SELECT market_cap
FROM market_data
WHERE date = '2023-05-02';
